using System;
using System.Collections.Generic;
using System.Drawing;
using System.IO;
using System.Windows.Forms;

namespace Tunetoon.Forms
{
    public class ComboForm : Form
    {
        private static readonly string ImgToon   = "";
        private static readonly string ImgCogLow = "";
        private static readonly string ImgCogMid = "";
        private static readonly string ImgCogHigh= "";
        private static readonly string ImgCogMax = "";

        private Image _imgToon, _imgCogLow, _imgCogMid, _imgCogHigh, _imgCogMax;

        private int _toonCount = 4;
        private int _cogCount  = 4;

        private Button[] _toonSq  = new Button[4];
        private Button[] _cogSq   = new Button[4];
        private PictureBox[] _cogPic  = new PictureBox[4];
        private NumericUpDown[] _cogLevel = new NumericUpDown[4];
        private Panel[] _cogPanel = new Panel[4];
        private PictureBox[] _gagPic  = new PictureBox[4];
        private Label[] _gagName   = new Label[4];
        private Label[] _gagToon   = new Label[4];
        private Panel[] _gagPanel  = new Panel[4];
        private Panel _arrowPanel;
        private Label _comboNote;
        private Button _calcBtn;

        private readonly Color BG        = Color.FromArgb(26, 26, 46);
        private readonly Color BG2       = Color.FromArgb(37, 37, 69);
        private readonly Color BG_COG    = Color.FromArgb(42, 26, 26);
        private readonly Color BG_GAG    = Color.FromArgb(26, 42, 26);
        private readonly Color ACCENT    = Color.FromArgb(158, 202, 216);
        private readonly Color ACCENT2   = Color.FromArgb(200, 228, 240);
        private readonly Color COG_BORDER= Color.FromArgb(90, 42, 42);
        private readonly Color GAG_BORDER= Color.FromArgb(42, 90, 42);
        private readonly Color TEXT_COG  = Color.FromArgb(204, 136, 136);
        private readonly Color TEXT_GAG  = Color.FromArgb(136, 221, 136);
        private readonly Color TEXT_DIM  = Color.FromArgb(85, 85, 102);

        public ComboForm()
        {
            LoadImages();
            BuildUI();
        }

        private Image FromB64(string b64) =>
            Image.FromStream(new MemoryStream(Convert.FromBase64String(b64)));

        private void LoadImages()
        {
            _imgToon    = FromB64(ImgToon);
            _imgCogLow  = FromB64(ImgCogLow);
            _imgCogMid  = FromB64(ImgCogMid);
            _imgCogHigh = FromB64(ImgCogHigh);
            _imgCogMax  = FromB64(ImgCogMax);
        }

        private Image CogImage(int level)
        {
            if (level <= 4)  return _imgCogLow;
            if (level <= 9)  return _imgCogMid;
            if (level <= 11) return _imgCogHigh;
            return _imgCogMax;
        }

        private void BuildUI()
        {
            Text            = "Combo Calculator";
            FormBorderStyle = FormBorderStyle.FixedSingle;
            StartPosition   = FormStartPosition.CenterScreen;
            BackColor       = BG;
            MaximizeBox     = false;
            MinimizeBox     = false;
            ClientSize      = new Size(660, 520);

            // Title
            var title = new Label
            {
                Text      = "Combo Calculator",
                ForeColor = ACCENT,
                Font      = new Font("Segoe UI", 13f, FontStyle.Regular),
                Location  = new Point(16, 12),
                AutoSize  = true,
            };

            // separator
            var sep = new Panel { BackColor = Color.FromArgb(42,42,74), Location = new Point(16,38), Size = new Size(628,1) };

            // ── Selectors row ──────────────────────────────────────────────
            var lblToons = MakeLabel("Toons", TEXT_DIM, 11f, new Point(16, 52));
            var lblCogs  = MakeLabel("Cogs",  TEXT_DIM, 11f, new Point(340, 52));

            for (int i = 0; i < 4; i++)
            {
                int ti = i;
                _toonSq[i] = MakeSquare((i+1).ToString(), i == 3, new Point(16 + i*54, 70), true);
                _toonSq[i].Click += (s,e) => OnSquareClick(_toonSq, ti, true);

                _cogSq[i] = MakeSquare((i+1).ToString(), i == 3, new Point(340 + i*54, 70), true);
                _cogSq[i].Click += (s,e) => OnSquareClick(_cogSq, ti, false);
            }

            // ── Separator ─────────────────────────────────────────────────
            var sep2 = new Panel { BackColor = Color.FromArgb(42,42,74), Location = new Point(16,122), Size = new Size(628,1) };

            var lblCogLevels = MakeLabel("Cog Levels", TEXT_DIM, 11f, new Point(16, 132));

            // ── Cog slots ─────────────────────────────────────────────────
            for (int i = 0; i < 4; i++)
            {
                int ci = i;
                int x = 16 + i * 162;

                _cogPanel[i] = new Panel
                {
                    Location  = new Point(x, 150),
                    Size      = new Size(152, 110),
                    BackColor = BG_COG,
                };
                _cogPanel[i].Paint += (s,e) => PaintBorder(s, e, COG_BORDER);

                _cogPic[i] = new PictureBox
                {
                    Image    = CogImage(7),
                    SizeMode = PictureBoxSizeMode.StretchImage,
                    Size     = new Size(56, 56),
                    Location = new Point(48, 8),
                    BackColor= Color.Transparent,
                };

                var cogLabel = new Label
                {
                    Text      = $"Cog {i+1}",
                    ForeColor = TEXT_COG,
                    Font      = new Font("Segoe UI", 8.5f),
                    Location  = new Point(0, 68),
                    Size      = new Size(152, 18),
                    TextAlign = ContentAlignment.MiddleCenter,
                };

                _cogLevel[i] = new NumericUpDown
                {
                    Minimum   = 1,
                    Maximum   = 20,
                    Value     = 7,
                    Font      = new Font("Segoe UI", 14f, FontStyle.Bold),
                    Location  = new Point(44, 82),
                    Size      = new Size(64, 28),
                    BackColor = Color.FromArgb(26, 10, 10),
                    ForeColor = Color.FromArgb(255, 153, 153),
                    TextAlign = HorizontalAlignment.Center,
                    BorderStyle = BorderStyle.FixedSingle,
                };
                _cogLevel[i].ValueChanged += (s,e) =>
                {
                    _cogPic[ci].Image = CogImage((int)_cogLevel[ci].Value);
                };

                _cogPanel[i].Controls.AddRange(new Control[] { _cogPic[i], cogLabel, _cogLevel[i] });
            }

            // ── Arrow panel ───────────────────────────────────────────────
            _arrowPanel = new Panel
            {
                Location  = new Point(16, 268),
                Size      = new Size(628, 40),
                BackColor = Color.Transparent,
            };
            _arrowPanel.Paint += ArrowPanel_Paint;

            // ── Gag slots ─────────────────────────────────────────────────
            var lblGags = MakeLabel("Gags", TEXT_DIM, 11f, new Point(16, 314));

            for (int i = 0; i < 4; i++)
            {
                int x = 16 + i * 162;

                _gagPanel[i] = new Panel
                {
                    Location  = new Point(x, 332),
                    Size      = new Size(152, 100),
                    BackColor = BG_GAG,
                };
                _gagPanel[i].Paint += (s,e) => PaintBorder(s, e, GAG_BORDER);

                _gagPic[i] = new PictureBox
                {
                    SizeMode  = PictureBoxSizeMode.StretchImage,
                    Size      = new Size(44, 44),
                    Location  = new Point(54, 8),
                    BackColor = Color.Transparent,
                };

                _gagName[i] = new Label
                {
                    Text      = "Aoogah",
                    ForeColor = TEXT_GAG,
                    Font      = new Font("Segoe UI", 10f, FontStyle.Bold),
                    Location  = new Point(0, 56),
                    Size      = new Size(152, 20),
                    TextAlign = ContentAlignment.MiddleCenter,
                };

                _gagToon[i] = new Label
                {
                    Text      = $"Toon {i+1}",
                    ForeColor = TEXT_DIM,
                    Font      = new Font("Segoe UI", 8.5f),
                    Location  = new Point(0, 76),
                    Size      = new Size(152, 18),
                    TextAlign = ContentAlignment.MiddleCenter,
                };

                _gagPanel[i].Controls.AddRange(new Control[] { _gagPic[i], _gagName[i], _gagToon[i] });
            }

            // ── Note ──────────────────────────────────────────────────────
            _comboNote = new Label
            {
                Text      = "Sound gags hit all Cogs — no targeting needed",
                ForeColor = TEXT_DIM,
                Font      = new Font("Segoe UI", 9f),
                Location  = new Point(16, 438),
                Size      = new Size(628, 20),
                TextAlign = ContentAlignment.MiddleCenter,
            };

            // ── Calc button ───────────────────────────────────────────────
            _calcBtn = new Button
            {
                Text      = "Calculate Combo",
                Location  = new Point(16, 464),
                Size      = new Size(628, 36),
                BackColor = Color.FromArgb(26, 58, 42),
                ForeColor = Color.FromArgb(136, 221, 170),
                Font      = new Font("Segoe UI", 11f),
                FlatStyle = FlatStyle.Flat,
                Cursor    = Cursors.Hand,
            };
            _calcBtn.FlatAppearance.BorderColor = Color.FromArgb(42, 106, 74);
            _calcBtn.Click += CalcBtn_Click;

            Controls.AddRange(new Control[] {
                title, sep, lblToons, lblCogs, sep2, lblCogLevels,
                _arrowPanel, lblGags, _comboNote, _calcBtn
            });
            foreach (var sq in _toonSq) Controls.Add(sq);
            foreach (var sq in _cogSq)  Controls.Add(sq);
            foreach (var p  in _cogPanel) Controls.Add(p);
            foreach (var p  in _gagPanel) Controls.Add(p);

            UpdateSquares(_toonSq, _toonCount, true);
            UpdateSquares(_cogSq,  _cogCount,  false);
            UpdateGagImages();
        }

        private void ArrowPanel_Paint(object sender, PaintEventArgs e)
        {
            // Para combos AoE (Sound), desenha linha horizontal indicando todos
            var g = e.Graphics;
            using var pen = new Pen(Color.FromArgb(158, 202, 216), 1.5f);
            pen.DashStyle = System.Drawing.Drawing2D.DashStyle.Dash;
            int y = 20;
            g.DrawLine(pen, 0, y, 628, y);
            using var br = new SolidBrush(Color.FromArgb(85, 158, 202, 216));
            g.FillEllipse(br, 280, y-6, 12, 12);
            using var font = new Font("Segoe UI", 8f);
            using var tbr = new SolidBrush(Color.FromArgb(158, 202, 216));
            g.DrawString("hits all", font, tbr, 298, y-8);
        }

        private void PaintBorder(object sender, PaintEventArgs e, Color color)
        {
            var ctrl = (Control)sender;
            using var pen = new Pen(color, 1.5f);
            e.Graphics.DrawRectangle(pen, 0, 0, ctrl.Width-1, ctrl.Height-1);
        }

        private void OnSquareClick(Button[] sqs, int idx, bool isToon)
        {
            if (idx == 3)
            {
                bool allOn = Array.TrueForAll(sqs, s => s.Tag?.ToString() == "on");
                int newCount = allOn ? 0 : 4;
                if (isToon) _toonCount = newCount; else _cogCount = newCount;
                UpdateSquares(sqs, allOn ? 0 : 4, isToon);
            }
            else
            {
                int cur = isToon ? _toonCount : _cogCount;
                int newCount = idx < cur ? idx : idx + 1;
                if (isToon) _toonCount = newCount; else _cogCount = newCount;
                UpdateSquares(sqs, newCount, isToon);
            }
        }

        private void UpdateSquares(Button[] sqs, int count, bool isToon)
        {
            for (int i = 0; i < 4; i++)
            {
                bool on = i < count;
                sqs[i].Tag       = on ? "on" : "off";
                sqs[i].BackColor = on ? ACCENT : BG2;
                sqs[i].ForeColor = on ? BG : ACCENT;
            }
            if (isToon)
            {
                for (int i = 0; i < 4; i++)
                    _gagPanel[i].Visible = i < count;
                _toonCount = count;
            }
            else
            {
                for (int i = 0; i < 4; i++)
                    _cogPanel[i].Visible = i < count;
                _cogCount = count;
            }
        }

        private void UpdateGagImages()
        {
            // placeholder — será preenchido quando as imagens de gag forem fornecidas
            for (int i = 0; i < 4; i++)
            {
                _gagPic[i].Image = null;
                _gagName[i].Text = "Aoogah";
                _gagToon[i].Text = $"Toon {i+1}";
            }
        }

        private void CalcBtn_Click(object sender, EventArgs e)
        {
            // lookup de combo — será implementado com os dados fornecidos
            int toons = _toonCount;
            int[] levels = new int[_cogCount];
            for (int i = 0; i < _cogCount; i++)
                levels[i] = (int)_cogLevel[i].Value;

            // Exemplo: 4 toons + 4 cogs level 7 = 4x Aoogah
            bool allSeven = toons == 4 && _cogCount == 4 && Array.TrueForAll(levels, l => l == 7);
            if (allSeven)
            {
                for (int i = 0; i < 4; i++)
                    _gagName[i].Text = "Aoogah";
                _comboNote.Text = "Sound gags hit all Cogs — no targeting needed";
            }
        }

        private Button MakeSquare(string text, bool isLast, Point loc, bool startOn)
        {
            var btn = new Button
            {
                Text      = text,
                Location  = loc,
                Size      = new Size(44, 44),
                BackColor = startOn ? ACCENT : BG2,
                ForeColor = startOn ? BG : (isLast ? ACCENT2 : ACCENT),
                Font      = new Font("Segoe UI", 12f, FontStyle.Bold),
                FlatStyle = FlatStyle.Flat,
                Cursor    = Cursors.Hand,
                Tag       = startOn ? "on" : "off",
            };
            btn.FlatAppearance.BorderColor = isLast ? ACCENT2 : ACCENT;
            btn.FlatAppearance.BorderSize  = 1;
            return btn;
        }

        private Label MakeLabel(string text, Color color, float size, Point loc) =>
            new Label
            {
                Text      = text.ToUpper(),
                ForeColor = color,
                Font      = new Font("Segoe UI", size),
                Location  = loc,
                AutoSize  = true,
            };
    }
}
